  ('real-estate-moex-02392', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '曾經營不動產經紀業，經主管機關撤銷或廢止許可，原則上自撤銷或廢止之日起未滿多少年者，不得申請 經營經紀業？', '["一年", "三年", "五年", "十年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02393', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業以契約、協議或其他方式之合意，與有競爭關係之他事業共同決定商品或服務之價格，或限制數量、 技術、產品、設備、交易對象、交易地區等，相互約束事業活動之行為。稱為：', '["結合", "聯合行為", "多層次傳銷", "獨占"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02394', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業因結合而使其市場占有率達多少以上者，其結合應先向中央主管機關提出申報？', '["二分之一", "三分之一", "四分之一", "五分之一"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02395', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業對於其交易相對人，就供給之商品轉售與第三人或第三人再轉售時，其售價：', '["應容許其自由決定", "限制其不得逾原供給價格之百分之一百一十", "限制其不得逾原供給價格之百分之一百三十", "限制其不得逾原供給價格之百分之一百五十"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02396', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業之結合，依規定應先向中央主管機關申報者，除情形特殊經中央主管機關通知縮短或延長期間者外， 自中央主管機關受理其提出完整申報資料之日起多少時日內，不得為結合？', '["三十日", "六十日", "九十日", "六個月"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02397', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '獨占事業以不公平之方法，直接或間接阻礙他事業參與競爭，經中央主管機關限期命其停止，而逾期未 停止者，處行為人多少金額（新臺幣）以下之罰金？', '["一千萬元", "三千萬元", "五千萬元", "一億元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02398', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '多層次傳銷參加人退出多層次傳銷組織，下列敘述，何者錯誤？', '["得以解除契約或終止契約之方式為之", "解除契約之期限，為自訂定契約之日起十四日內", "終止契約之期限，為自訂定契約之日起一年內", "參加人行使契約解除權或終止權時，多層次傳銷事業不得向參加人請求違約金"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02399', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業違反公平交易法之規定，致侵害他人權益者，被害人損害賠償之請求權，自請求權人知有行為及賠償 義務人時起，二年間不行使而消滅；自行為時起，逾多少時日者，亦同？', '["二年", "三年", "五年", "十年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02400', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公平交易法規定所處停止營業之期間，每次以多少時日為限？', '["三個月", "六個月", "一年", "二年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02401', 'real-estate', 'real-estate-moex-098-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '事業得申請中央主管機關許可聯合行為，下列何者非屬法定得申請之情形？', '["為促進事業合理經營，而分別作專業發展者", "為確保或促進輸出，而專就國外市場之競爭予以約定者", "為加強貿易效能，而就國外商品之輸入採取共同行為者", "為保障事業合理利潤，由同業公會協調決定商品價格者"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "e119da536ab8", "answer_pdf_sha1": "b6fab8935bc8", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "601", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
